  3→/// Creates a transaction hash from the given input and output compressed account hashes and the current slot.
  4→///
  5→/// # Parameters
  6→/// - `input_compressed_account_hashes`: A slice of input compressed account hashes.
  7→/// - `output_compressed_account_hashes`: A slice of output compressed account hashes.
  8→/// - `current_slot`: The current slot as a 64-bit unsigned integer.
  9→pub fn create_tx_hash(
 10→    input_compressed_account_hashes: &[[u8; 32]],
 11→    output_compressed_account_hashes: &[[u8; 32]],
 12→    current_slot: u64,
 13→) -> Result<[u8; 32], CompressedAccountError> {
 14→    let version = [0u8; 32];
 15→    let mut current_slot_bytes = [0u8; 32];
 16→    current_slot_bytes[24..].copy_from_slice(&current_slot.to_be_bytes());
 17→    let inputs_hash_chain = create_hash_chain_from_slice(input_compressed_account_hashes)?;
 18→    let outputs_hash_chain = create_hash_chain_from_slice(output_compressed_account_hashes)?;
 19→    let hash_chain = create_hash_chain_from_slice(&[
 20→        version,
 21→        inputs_hash_chain,
 22→        outputs_hash_chain,
 23→        current_slot_bytes,
 24→    ])?;
 25→    Ok(hash_chain)
 26→}
 27→
 28→pub fn create_tx_hash_from_hash_chains(
 29→    inputs_hash_chain: &[u8; 32],
 30→    outputs_hash_chain: &[u8; 32],
 31→    current_slot: u64,
 32→) -> Result<[u8; 32], CompressedAccountError> {
 33→    let version = [0u8; 32];
 34→    let mut current_slot_bytes = [0u8; 32];
 35→    current_slot_bytes[24..].copy_from_slice(&current_slot.to_be_bytes());
 36→    let hash_chain = create_hash_chain_from_slice(&[
 37→        version,
 38→        *inputs_hash_chain,
 39→        *outputs_hash_chain,
 40→        current_slot_bytes,
 41→    ])?;
 42→    Ok(hash_chain)
 43→}
