 36→    }
 37→
 38→    pub fn new<const HEIGHT: usize>(
 39→        tree_result: BatchTreeUpdateResult,
 40→        tx_hashes: &[[u8; 32]],
 41→        leaves: &[[u8; 32]],
 42→        leaves_hashchain: [u8; 32],
 43→        path_indices: &[u32],
 44→        batch_size: u32,
 45→    ) -> Result<Self, ProverClientError> {
 46→        let batch_size_usize = batch_size as usize;
 47→        if leaves.len() != batch_size_usize
 48→            || tree_result.old_leaves.len() != batch_size_usize
 49→            || tree_result.merkle_proofs.len() != batch_size_usize
 50→            || tx_hashes.len() != batch_size_usize
 51→            || path_indices.len() != batch_size_usize
 52→        {
 53→            return Err(ProverClientError::GenericError(format!(
 54→                "Input vector length mismatch: leaves={}, old_leaves={}, merkle_proofs={}, tx_hashes={}, path_indices={}, expected batch_size={}",
 55→                leaves.len(), tree_result.old_leaves.len(), tree_result.merkle_proofs.len(), tx_hashes.len(), path_indices.len(), batch_size
 56→            )));
 57→        }
 58→
 59→        let mut circuit_merkle_proofs = Vec::with_capacity(batch_size_usize);
 60→
 61→        for merkle_proof in tree_result.merkle_proofs.into_iter() {
 62→            let proof_len = merkle_proof.len();
 63→            let merkle_proof_array: [[u8; 32]; HEIGHT] =
 64→                merkle_proof.as_slice().try_into().map_err(|_| {
 65→                    ProverClientError::GenericError(format!(
 66→                        "Invalid merkle proof length: got {}, expected {}",
 67→                        proof_len, HEIGHT
 68→                    ))
 69→                })?;
 70→
 71→            circuit_merkle_proofs.push(
 72→                merkle_proof_array
 73→                    .iter()
 74→                    .map(|proof_elem| BigInt::from_bytes_be(Sign::Plus, proof_elem))
 75→                    .collect(),
 76→            );
 77→        }
 78→
 79→        let public_input_hash = create_hash_chain_from_array([
 80→            tree_result.old_root,
 81→            tree_result.new_root,
 82→            leaves_hashchain,
 83→        ])?;
 84→
 85→        Ok(Self {
 86→            public_input_hash: BigInt::from_bytes_be(Sign::Plus, &public_input_hash),
 87→            old_root: BigInt::from_bytes_be(Sign::Plus, &tree_result.old_root),
 88→            new_root: BigInt::from_bytes_be(Sign::Plus, &tree_result.new_root),
 89→            tx_hashes: tx_hashes
 90→                .iter()
 91→                .map(|tx| BigInt::from_bytes_be(Sign::Plus, tx))
 92→                .collect(),
 93→            leaves_hashchain_hash: BigInt::from_bytes_be(Sign::Plus, &leaves_hashchain),
 94→            leaves: leaves
 95→                .iter()
 96→                .map(|leaf| BigInt::from_bytes_be(Sign::Plus, leaf))
 97→                .collect(),
 98→            old_leaves: tree_result
 99→                .old_leaves
100→                .iter()
101→                .map(|leaf| BigInt::from_bytes_be(Sign::Plus, leaf))
102→                .collect(),
103→            merkle_proofs: circuit_merkle_proofs,
104→            path_indices: path_indices.to_vec(),
105→            height: HEIGHT as u32,
106→            batch_size,
107→        })
108→    }
109→}
