122→pub fn get_batch_update_inputs<const HEIGHT: usize>(
123→    current_root: [u8; 32],
124→    tx_hashes: Vec<[u8; 32]>,
125→    leaves: Vec<[u8; 32]>,
126→    leaves_hashchain: [u8; 32],
127→    old_leaves: Vec<[u8; 32]>,
128→    merkle_proofs: Vec<Vec<[u8; 32]>>,
129→    path_indices: Vec<u32>,
130→    batch_size: u32,
131→    previous_changelogs: &[ChangelogEntry<HEIGHT>],
132→) -> Result<(BatchUpdateCircuitInputs, Vec<ChangelogEntry<HEIGHT>>), ProverClientError> {
133→    let mut new_root = [0u8; 32];
134→    let old_root = current_root;
135→    let mut changelog: Vec<ChangelogEntry<HEIGHT>> = Vec::new();
136→    let mut circuit_merkle_proofs = vec![];
137→    let mut adjusted_path_indices = Vec::with_capacity(leaves.len());
138→
139→    for (i, (leaf, (mut merkle_proof, index))) in leaves
140→        .iter()
141→        .zip(merkle_proofs.into_iter().zip(path_indices.iter()))
142→        .enumerate()
143→    {
144→        adjusted_path_indices.push(*index);
145→
146→        // Update the proof with changelogs from previous batches.
147→        for entry in previous_changelogs.iter() {
148→            entry
149→                .update_proof(*index as usize, &mut merkle_proof)
150→                .map_err(|e| {
151→                    ProverClientError::GenericError(format!(
152→                        "Failed to update proof with previous changelog: {:?}",
153→                        e
154→                    ))
155→                })?;
156→        }
157→        // And update with current batch changelogs accumulated so far.
158→        if i > 0 {
159→            for entry in changelog.iter() {
160→                entry
161→                    .update_proof(*index as usize, &mut merkle_proof)
162→                    .map_err(|e| {
163→                        ProverClientError::GenericError(format!(
164→                            "Failed to update proof with previous changelog: {:?}",
165→                            e
166→                        ))
167→                    })?;
168→            }
169→        }
170→
171→        let merkle_proof_array = merkle_proof.try_into().unwrap();
172→
173→        // Use the adjusted index bytes for computing the nullifier.
174→        let index_bytes = (*index).to_be_bytes();
175→        let nullifier = Poseidon::hashv(&[leaf, &index_bytes, &tx_hashes[i]]).unwrap();
176→        let (root, changelog_entry) =
177→            compute_root_from_merkle_proof(nullifier, &merkle_proof_array, *index);
178→        new_root = root;
179→        changelog.push(changelog_entry);
180→        circuit_merkle_proofs.push(
181→            merkle_proof_array
182→                .iter()
183→                .map(|hash| BigInt::from_bytes_be(Sign::Plus, hash))
184→                .collect(),
185→        );
186→    }
187→
188→    // Compute the public input hash as the chain of (old_root, new_root, leaves_hashchain)
189→    // (this must match the BatchUpdateCircuit in the prover, which expects exactly three inputs).
190→    let public_input_hash = create_hash_chain_from_array([old_root, new_root, leaves_hashchain])?;
191→
192→    let inputs = BatchUpdateCircuitInputs {
193→        public_input_hash: BigInt::from_bytes_be(Sign::Plus, &public_input_hash),
194→        old_root: BigInt::from_bytes_be(Sign::Plus, &old_root),
195→        new_root: BigInt::from_bytes_be(Sign::Plus, &new_root),
196→        tx_hashes: tx_hashes
197→            .into_iter()
198→            .map(|tx| BigInt::from_bytes_be(Sign::Plus, &tx))
199→            .collect(),
200→        leaves_hashchain_hash: BigInt::from_bytes_be(Sign::Plus, &leaves_hashchain),

