 6→/// Light discriminator: SHA256("{name}")[0..8]
 7→/// Implements LightDiscriminator trait
 8→pub(crate) fn light_discriminator(input: ItemStruct) -> Result<TokenStream> {
 9→    let account_name = &input.ident;
10→    let hash_input = account_name.to_string();
11→
12→    let (impl_gen, type_gen, where_clause) = input.generics.split_for_impl();
13→
14→    let mut discriminator = [0u8; 8];
15→    discriminator.copy_from_slice(&Sha256::hash(hash_input.as_bytes()).unwrap()[..8]);
16→    let discriminator: proc_macro2::TokenStream = format!("{discriminator:?}").parse().unwrap();
17→
18→    Ok(quote! {
19→        impl #impl_gen LightDiscriminator for #account_name #type_gen #where_clause {
20→            const LIGHT_DISCRIMINATOR: [u8; 8] = #discriminator;
21→            const LIGHT_DISCRIMINATOR_SLICE: &'static [u8] = &Self::LIGHT_DISCRIMINATOR;
22→
23→            fn discriminator() -> [u8; 8] {
24→                Self::LIGHT_DISCRIMINATOR
25→            }
26→        }
27→    })
28→}
