 19→/// Hashes the input compressed accounts and stores the results in the leaves array.
 20→/// Merkle tree pubkeys are hashed and stored in the hashed_pubkeys array.
 21→/// Merkle tree pubkeys should be ordered for efficiency.
 22→#[inline(always)]
 23→#[profile]
 24→pub fn create_inputs_cpi_data<'a, 'info, T: InstructionData<'a>>(
 25→    remaining_accounts: &'info [AccountInfo],
 26→    instruction_data: &WrappedInstructionData<'a, T>,
 27→    context: &mut SystemContext<'info>,
 28→    cpi_ix_data: &mut InsertIntoQueuesInstructionDataMut<'_>,
 29→    accounts: &[AcpAccount<'info>],
 30→) -> Result<[u8; 32]> {
 31→    if instruction_data.inputs_empty() {
 32→        return Ok([0u8; 32]);
 33→    }
 34→    let mut owner_pubkey = instruction_data.owner();
 35→    let mut hashed_owner = hash_to_bn254_field_size_be(&owner_pubkey.to_bytes());
 36→    context
 37→        .hashed_pubkeys
 38→        .push((owner_pubkey.into(), hashed_owner));
 39→    let mut current_hashed_mt = [0u8; 32];
 40→    let mut hash_chain = [0u8; 32];
 41→
 42→    let mut current_mt_index: u8 = 0;
 43→    let mut is_first_iter = true;
 44→    let mut seq_index = 0;
 45→    let mut is_batched = true;
 46→    for (j, input_compressed_account_with_context) in instruction_data.input_accounts().enumerate()
 47→    {
 48→        context
 49→            .addresses
 50→            .push(input_compressed_account_with_context.address());
 51→
 52→        let merkle_context = input_compressed_account_with_context.merkle_context();
 53→        #[allow(clippy::comparison_chain)]
 54→        if current_mt_index != merkle_context.merkle_tree_pubkey_index || is_first_iter {
 55→            is_first_iter = false;
 56→            current_mt_index = merkle_context.merkle_tree_pubkey_index;
 57→            current_hashed_mt = match &accounts
 58→                .get(current_mt_index as usize)
 59→                .ok_or(SystemProgramError::InputMerkleTreeIndexOutOfBounds)?
 60→            {
 61→                AcpAccount::BatchedStateTree(tree) => {
 62→                    context.set_network_fee_v2(
 63→                        tree.metadata.rollover_metadata.network_fee,
 64→                        current_mt_index,
 65→                    );
 66→                    is_batched = true;
 67→                    // We only set sequence number for batched input queues.
 68→                    cpi_ix_data.insert_input_sequence_number(
 69→                        &mut seq_index,
 70→                        tree.pubkey(),
 71→                        &tree.metadata.associated_queue,
 72→                        tree.tree_type,
 73→                        tree.queue_batches.next_index,
 74→                    );
 75→                    tree.hashed_pubkey
 76→                }
 77→                AcpAccount::StateTree(_) => {
 78→                    is_batched = false;
 79→                    let legacy_context = context
 80→                        .get_legacy_merkle_context(current_mt_index)
 81→                        .ok_or(SystemProgramError::MissingLegacyMerkleContext)?;
 82→                    let network_fee = legacy_context.network_fee;
 83→                    let hashed_pubkey = legacy_context.hashed_pubkey;
 84→                    context.set_network_fee_v1(network_fee, current_mt_index)?;
 85→                    hashed_pubkey
 86→                }
 87→                _ => {
 88→                    msg!(format!("create_inputs_cpi_data {} ", current_mt_index).as_str());
 89→                    return Err(
 90→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
 91→                    );
 92→                }
 93→            };
 94→        }
 95→        // Without cpi context all input compressed accounts have the same owner.
 96→        // With cpi context the owners will be different.
 97→        if owner_pubkey != *input_compressed_account_with_context.owner() {
 98→            owner_pubkey = *input_compressed_account_with_context.owner();
 99→            hashed_owner = context.get_or_hash_pubkey(owner_pubkey.into());
100→        }
101→        let merkle_context = input_compressed_account_with_context.merkle_context();
102→        let queue_index = context.get_index_or_insert(
103→            merkle_context.queue_pubkey_index,
104→            remaining_accounts,
105→            "Input queue (nullifier queue for V1 state trees, output queue for V2 state trees)",
106→        )?;
107→        let tree_index = context.get_index_or_insert(
108→            merkle_context.merkle_tree_pubkey_index,
109→            remaining_accounts,
110→            "Input tree",
111→        )?;
112→
113→        cpi_ix_data.nullifiers[j] = InsertNullifierInput {
114→            account_hash: input_compressed_account_with_context
115→                .hash_with_hashed_values(
116→                    &hashed_owner,
117→                    &current_hashed_mt,
118→                    &merkle_context.leaf_index.into(),
119→                    is_batched,
120→                )
121→                .map_err(ProgramError::from)?,
122→            leaf_index: merkle_context.leaf_index,
123→            prove_by_index: merkle_context.prove_by_index() as u8,
124→            queue_index,
125→            tree_index,
126→        };
127→        if j == 0 {
128→            hash_chain = cpi_ix_data.nullifiers[j].account_hash;
129→        } else {
130→            hash_chain = Poseidon::hashv(&[&hash_chain, &cpi_ix_data.nullifiers[j].account_hash])
131→                .map_err(ProgramError::from)?;
132→        }
133→    }
134→    // TODO: benchmark the chaining.
135→    cpi_ix_data.num_queues = instruction_data
136→        .input_accounts()
137→        .enumerate()
138→        .filter(|(i, x)| {
139→            let candidate = x.merkle_context().queue_pubkey_index;
140→            !instruction_data
141→                .input_accounts()
142→                .take(*i)
143→                .any(|y| y.merkle_context().queue_pubkey_index == candidate)
144→        })
145→        .count() as u8;
146→
147→    Ok(hash_chain)
148→}
